const { exec } = require('child_process');
const { BlobServiceClient, StorageSharedKeyCredential } = require('@azure/storage-blob');

exports.runConversion = async function (context, req) {
    const inputFilename = req.body.inputFilename;
    const outputFormat = req.body.outputFormat;

    if (!inputFilename || !outputFormat) {
        context.log.error('Missing required parameters');
        return { statusCode: 400 };
    }

    try {
        const storageAccountName = 'your_storage_account_name';
        const storageAccountKey = 'your_storage_account_key';
        const containerName = 'your_container_name';

        const credential = new StorageSharedKeyCredential(storageAccountName, storageAccountKey);
        const blobServiceClient = new BlobServiceClient(credential, `https://${storageAccountName}.blob.core.windows.net`);

        const containerClient = blobServiceClient.getContainerClient(containerName);

        if (!(await containerClient.exists())) {
            await containerClient.create();
        }

        const inputBlobName = `${inputFilename}.${outputFormat}`;
        const outputBlobName = `${inputFilename}_converted.${outputFormat}`;

        const inputFileUrl = `https://${storageAccountName}.blob.core.windows.net/${containerName}/${inputFilename}`;
        const outputFileUrl = `https://${storageAccountName}.blob.core.windows.net/${containerName}/${outputBlobName}`;

        const libreOfficePath = '/path/to/libreoffice';
        const command = `${libreOfficePath}/soffice --headless --convert-to ${outputFormat} --outdir /tmp ${inputFileUrl}`;

        exec(command, (error) => {
            if (error) {
                context.log.error('Error running LibreOffice:', error);
                return { statusCode: 500 };
            }

            const downloadOptions = {
                blobURL: outputFileUrl,
                containerName,
                storageAccountName
            };

            const downloadResponse = await downloadBlob(downloadOptions);

            if (!downloadResponse.success) {
                context.log.error('Error downloading converted file:', downloadResponse.error);
                return { statusCode: 500 };
            }

            const outputBuffer = Buffer.from(downloadResponse.data, 'binary');
            const outputFilename = `${outputBlobName}.${outputFormat}`;

            const blobClient = containerClient.getBlockBlobClient(outputFilename);
            await blobClient.uploadData(outputBuffer);

            context.log.info(`Conversion complete. Output file saved as ${outputFilename}`);
        });
    } catch (error) {
        context.log.error('Error running conversion:', error);
        return { statusCode: 500 };
    }
};

async function downloadBlob(options) {
    const storageAccountName = options.storageAccountName;
    const containerName = options.containerName;
    const blobURL = options.blobURL;

    try {
        const credential = new StorageSharedKeyCredential(storageAccountName, 'your_storage_account_key');
        const blobServiceClient = new BlobServiceClient(credential, `https://${storageAccountName}.blob.core.windows.net`);

        const containerClient = blobServiceClient.getContainerClient(containerName);
        const blobClient = containerClient.getBlockBlobClient(blobURL.split('/').pop());

        const downloadResponse = await blobClient.downloadToBuffer();
        return { success: true, data: downloadResponse.data };
    } catch (error) {
        return { success: false, error };
    }
}